#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;
    int n = (int)s.size();

    // Find the fulcrum position
    int pivot = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '^') {
            pivot = i;
            break;
        }
    }

    long long torque = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] >= '1' && s[i] <= '9') {
            int weight = s[i] - '0';
            int dist = i - pivot;  // positive = right side, negative = left side
            torque += 1LL * weight * dist;
        }
    }

    if (torque < 0) {
        cout << "left\n";
    } else if (torque > 0) {
        cout << "right\n";
    } else {
        cout << "balance\n";
    }

    return 0;
}
